137.                 // requestFailedException.InnerException.HttpRequestError into error.type
138. 
139.                 string? errorCode = string.IsNullOrEmpty(requestFailedException.ErrorCode) ? null : requestFailedException.ErrorCode;
140.                 _activityAdapter?.MarkFailed(exception, errorCode);
141.             }
142.             else
