                             break;
                         case ActivityKind.Server:
                             AddTag("kind", "server");
                             break;
                         case ActivityKind.Client:
                             AddTag("kind", "client");
                             break;
                         case ActivityKind.Producer:
                             AddTag("kind", "producer");
                             break;
                         case ActivityKind.Consumer:
                             AddTag("kind", "consumer");
                             break;
