             }

             public void SetStartTime(DateTime startTime)
             {
                 _startTime = startTime;
                 _currentActivity?.SetStartTime(startTime);
             }

             public void MarkFailed<T>(T? exception, string? errorCode)
             {
                 if (errorCode == null && exception != null)
                 {
